const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();

const PORT = process.env.PORT || 3000;
const SESSION_SECRET = process.env.SESSION_SECRET || 'change-this-session-secret';
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || '';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || '';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '';

const twilioClient =
  TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN
    ? twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    : null;

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.use(
  session({
    secret: SESSION_SECRET,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      sameSite: 'lax',
      secure: false,
      maxAge: 10 * 60 * 1000
    }
  })
);

function generateSixDigitCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

function isValidPhoneNumber(phone) {
  return typeof phone === 'string' && /^\+?[1-9]\d{7,14}$/.test(phone);
}

async function sendSms(to, body) {
  if (!twilioClient) {
    console.log(`[DEV SMS] To: ${to} | Message: ${body}`);
    return { sid: 'dev-mode-message' };
  }

  return twilioClient.messages.create({
    body,
    from: TWILIO_PHONE_NUMBER,
    to
  });
}

function requirePending2FA(req, res, next) {
  if (!req.session.twoFactor || !req.session.twoFactor.phone) {
    return res.status(400).json({ error: 'No pending two-factor authentication session.' });
  }
  next();
}

app.post('/auth/2fa/send', async (req, res) => {
  try {
    const { phone } = req.body;

    if (!isValidPhoneNumber(phone)) {
      return res.status(400).json({ error: 'Invalid phone number.' });
    }

    const code = generateSixDigitCode();
    const expiresAt = Date.now() + 5 * 60 * 1000;

    req.session.twoFactor = {
      phone,
      code,
      expiresAt,
      verified: false,
      attempts: 0
    };

    await sendSms(phone, `Your verification code is: ${code}`);

    return res.status(200).json({
      message: 'Verification code sent successfully.',
      expiresInSeconds: 300
    });
  } catch (error) {
    console.error('Error sending 2FA code:', error);
    return res.status(500).json({ error: 'Failed to send verification code.' });
  }
});

app.post('/auth/2fa/verify', requirePending2FA, (req, res) => {
  const { code } = req.body;
  const twoFactor = req.session.twoFactor;

  if (!code || typeof code !== 'string') {
    return res.status(400).json({ error: 'Verification code is required.' });
  }

  if (twoFactor.verified) {
    return res.status(200).json({ message: 'Two-factor authentication already verified.' });
  }

  if (Date.now() > twoFactor.expiresAt) {
    req.session.twoFactor = null;
    return res.status(400).json({ error: 'Verification code has expired.' });
  }

  twoFactor.attempts += 1;

  if (twoFactor.attempts > 5) {
    req.session.twoFactor = null;
    return res.status(429).json({ error: 'Too many failed attempts. Please request a new code.' });
  }

  if (code !== twoFactor.code) {
    return res.status(401).json({
      error: 'Invalid verification code.',
      attemptsRemaining: Math.max(0, 5 - twoFactor.attempts)
    });
  }

  twoFactor.verified = true;
  twoFactor.verifiedAt = Date.now();

  return res.status(200).json({
    message: 'Two-factor authentication verified successfully.',
    authenticated: true
  });
});

app.get('/auth/2fa/status', (req, res) => {
  const twoFactor = req.session.twoFactor;

  if (!twoFactor) {
    return res.status(200).json({
      hasPending2FA: false,
      authenticated: false
    });
  }

  const expired = Date.now() > twoFactor.expiresAt;

  return res.status(200).json({
    hasPending2FA: true,
    phone: twoFactor.phone,
    authenticated: !!twoFactor.verified && !expired,
    expired
  });
});

app.post('/auth/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ error: 'Failed to clear session.' });
    }
    return res.status(200).json({ message: 'Logged out successfully.' });
  });
});

app.get('/', (req, res) => {
  res.json({
    message: 'SMS-based 2FA service is running.',
    endpoints: {
      sendCode: 'POST /auth/2fa/send',
      verifyCode: 'POST /auth/2fa/verify',
      status: 'GET /auth/2fa/status',
      logout: 'POST /auth/logout'
    }
  });
});

app.listen(PORT, () => {
  console.log(`2FA app listening on port ${PORT}`);
});